export class BlueprintLoader extends Component {
  static preferredTagName = 'tosi-loader';
  static lightStyleSpec = HIDDEN_STYLE;
  allLoaded = () => { };
  async load() {
    const blueprintElements = Array.from(this.querySelectorAll('tosi-blueprint, xin-blueprint')).filter((elt) => elt.src);
    const promises = blueprintElements.map((elt) => elt.packaged());
    await Promise.all(promises);
    this.allLoaded();
}
  connectedCallback() {
    super.connectedCallback();
    this.load();
}
}

export const tosiLoader = BlueprintLoader.elementCreator();

